# ❌ ANTI-PATTERN: Implicit tool calls without state tracking
class CricketBowlerAgent:
    def investigate_batting_strategy(self, query):
        # Loses context between calls, redundant API hits
        bowler_stats = fetch_bowler_data(query)
        venue_data = fetch_venue_data(query)  # Repeated work
        return combine_results(bowler_stats, venue_data)

# ✅ BEST PRACTICE: Explicit agentic loop with tool binding & checkpointing
class ResearchCricketAgent:
    def __init__(self):
        self.memory = CheckpointedMemory()
        self.tools = ToolRegistry([
            Tool("fetch_bowler_stats", fetch_bowler_data),
            Tool("fetch_venue_conditions", fetch_venue_data),
            Tool("rerank_documents", rerank_with_relevance)
        ])

    def investigate_batting_strategy(self, query):
        # Load prior state to avoid redundant calls
        cached_context = self.memory.retrieve(query_hash(query))
        if cached_context:
            return cached_context

        # Explicit tool binding with error handling
        try:
            bowler_docs = self.tools["fetch_bowler_stats"](query)
            reranked_bowlers = self.tools["rerank_documents"](
                bowler_docs, query, top_k=3
            )
            venue_docs = self.tools["fetch_venue_conditions"](query)

            reasoning = self.reason_about_strategy(
                reranked_bowlers, venue_docs
            )
            # Checkpoint result for future queries
            self.memory.checkpoint(query_hash(query), reasoning)
            return reasoning
        except ToolExecutionError as e:
            self.log_failure(query, e)
            raise
